struct Node {
    int data;
    struct Node* next;
};

int detectCycle(struct Node* head) {
    struct Node *slow = head, *fast = head;

    while (fast != NULL && fast->next != NULL) {
        slow = slow->next;
        fast = fast->next->next;

        if (slow == fast)
            return 1; // Cycle detected
    }
    return 0; // No cycle
}

def nth_from_end(head, n):
    first = head
    second = head

    # Move first pointer n positions ahead
    for i in range(n):
        if first is None:
            return None
        first = first.next

    # Move both pointers together
    while first:
        first = first.next
        second = second.next

    return second
